definition.script:
pipeline {
    agent any

    stages {
        stage('Step 1: Build & Update Image') {
            steps {
                echo '🔨 Собираем свежий образ сайта Nexthost...'
                sh 'cd /var/nexthost_project && docker build -t nexthost_app:latest .'
            }
        }
        stage('Step 2: Infrastructure Sync') {
            steps {
                echo '🚀 Синхронизируем контейнеры через Terraform...'
                // Добавили terraform init перед запуском!
                sh 'cd /var/nexthost_project && terraform init && terraform apply -auto-approve'
            }
        }
    }
    post {
        success {
            echo '✅ Красава! Все ресурсы обновлены успешно.'
        }
        failure {
            echo '❌ Ошибка! Проверь логи.'
        }
    }
}
